mapper.select:
select a.id as id, a.md5 as md5, a.job_id as job_id, b.name as job_name, b.class_name as class_name, a.job_group_id as job_group_id, c.name as job_group_name, a.cron_expression as cron_expression, a.next_execution_time as next_execution_time, a.enabled as enabled, a.last_execution_status as last_execution_status, a.create_time as create_time, a.update_time as update_time from sys_job_detail a left join sys_job b on a.job_id = b.id left join sys_job_group c on a.job_group_id = c.id
a.deleted = 1
and a.enabled = #{enabled}
and a.last_execution_status = #{lastExecutionStatus}
